import React, { useState, useEffect } from 'react';
import { useNavigate } from 'react-router-dom';
import { Sprout, ArrowLeft, MapPin, Loader, CloudRain, Thermometer, DollarSign } from 'lucide-react';
import { predictYield, getLocationWeather, getWeatherByCity, getLivePrices } from '../services/api';

const SLIDERS = [
  { key: 'rainfall',    label: 'Rainfall (mm)',            min: 200,  max: 1800, step: 10,  hint: 'Annual rainfall — auto-filled from GPS or enter manually' },
  { key: 'temperature', label: 'Temperature (°C)',          min: 8,    max: 42,   step: 0.5, hint: 'Average growing temperature — auto-filled from GPS' },
  { key: 'nitrogen',    label: 'Nitrogen (N) kg/ha',        min: 10,   max: 160,  step: 1,   hint: '' },
  { key: 'phosphorus',  label: 'Phosphorus (P) kg/ha',      min: 5,    max: 120,  step: 1,   hint: '' },
  { key: 'potassium',   label: 'Potassium (K) kg/ha',       min: 10,   max: 140,  step: 1,   hint: '' },
  { key: 'soil_ph',     label: 'Soil pH',                   min: 4.5,  max: 8.5,  step: 0.1, hint: 'Soil acidity/alkalinity level' },
  { key: 'fertilizer',  label: 'Fertilizer Amount (kg/ha)', min: 40,   max: 400,  step: 5,   hint: 'Total fertilizer application' },
];

const CROPS   = ["Maize","Wheat","Rice","Soybean","Barley","Sunflower","Cotton","Sugarcane"];
const SEASONS = ["Spring","Summer","Autumn","Winter"];

function sliderPct(val, min, max) { return ((val - min) / (max - min)) * 100; }

export default function InputForm() {
  const nav = useNavigate();
  const [form, setForm] = useState({
    crop: 'Maize', season: 'Autumn',
    rainfall: 650, temperature: 25, nitrogen: 50,
    phosphorus: 50, potassium: 50, soil_ph: 6.5, fertilizer: 175,
  });
  const [loading,      setLoading]      = useState(false);
  const [gpsLoading,   setGpsLoading]   = useState(false);
  const [cityInput,    setCityInput]    = useState('');
  const [cityLoading,  setCityLoading]  = useState(false);
  const [weatherInfo,  setWeatherInfo]  = useState(null);
  const [rainfallInfo, setRainfallInfo] = useState(null);
  const [prices,       setPrices]       = useState({});
  const [error,        setError]        = useState('');
  const [gpsError,     setGpsError]     = useState('');

  // Fetch live prices on mount
  useEffect(() => {
    getLivePrices().then(d => { if (d.prices) setPrices(d.prices); });
  }, []);

  const handleSlider = (key, val) => setForm(f => ({ ...f, [key]: parseFloat(val) }));

  // ── GPS auto-fill ──────────────────────────────────────────────────────────
  const handleGPS = async () => {
    setGpsLoading(true); setGpsError(''); setWeatherInfo(null); setRainfallInfo(null);
    try {
      const data = await getLocationWeather();
      if (data.current && !data.current.error) {
        setWeatherInfo(data.current);
        setForm(f => ({ ...f, temperature: data.current.temperature }));
      }
      if (data.historical && !data.historical.error) {
        setRainfallInfo(data.historical);
        setForm(f => ({ ...f, rainfall: Math.min(1800, Math.max(200, data.historical.annual_rainfall_mm)) }));
      } else if (data.current) {
        // Fallback: estimate from humidity if no historical data
        const estRain = Math.round(data.current.humidity * 12);
        setForm(f => ({ ...f, rainfall: Math.min(1800, Math.max(200, estRain)) }));
      }
    } catch (e) {
      setGpsError(e.message);
    } finally {
      setGpsLoading(false);
    }
  };

  // ── City search ────────────────────────────────────────────────────────────
  const handleCitySearch = async () => {
    if (!cityInput.trim()) return;
    setCityLoading(true); setGpsError(''); setWeatherInfo(null);
    try {
      const data = await getWeatherByCity(cityInput.trim());
      if (data.error) { setGpsError(data.error); return; }
      setWeatherInfo(data);
      setForm(f => ({ ...f, temperature: data.temperature }));
      // Also try historical by coordinates
      if (data.lat && data.lon) {
        const hist = await import('../services/api').then(m => m.getHistoricalRainfall(data.lat, data.lon));
        if (hist && !hist.error) {
          setRainfallInfo(hist);
          setForm(f => ({ ...f, rainfall: Math.min(1800, Math.max(200, hist.annual_rainfall_mm)) }));
        }
      }
    } catch (e) {
      setGpsError('Could not fetch weather. Check your API key in backend/.env');
    } finally {
      setCityLoading(false);
    }
  };

  // ── Submit ─────────────────────────────────────────────────────────────────
  const handleSubmit = async () => {
    setLoading(true); setError('');
    try {
      const result = await predictYield(form);
      sessionStorage.setItem('prediction',  JSON.stringify(result));
      sessionStorage.setItem('inputParams', JSON.stringify(form));
      nav('/dashboard');
    } catch (e) {
      setError('Prediction failed. Make sure ML service (port 8000) is running.');
    } finally {
      setLoading(false);
    }
  };

  const currentPrice = prices[form.crop];

  return (
    <div>
      <nav className="nav">
        <a className="nav-logo" href="/"><Sprout size={22} />AgriPredict</a>
        <button className="nav-back" onClick={() => nav(-1)}><ArrowLeft size={15} /> Back</button>
      </nav>

      <div className="page" style={{ maxWidth: 760 }}>
        <h1 className="page-title">Input Crop Parameters</h1>
        <p className="page-subtitle">Enter crop details — or use GPS to auto-fill weather data</p>

        {/* ── Live price banner ── */}
        {currentPrice && (
          <div style={{ background:'var(--green-50)', border:'1.5px solid var(--green-200)', borderRadius:10, padding:'10px 16px', display:'flex', alignItems:'center', gap:8, marginTop:'1rem', fontSize:'0.88rem' }}>
            <DollarSign size={15} color="var(--green-700)" />
            <span>Live World Bank price for <strong>{form.crop}</strong>: <strong>${currentPrice}/ton</strong></span>
            <span style={{ color:'var(--gray-400)', marginLeft:'auto' }}>Revenue will use real market price</span>
          </div>
        )}

        {/* ── GPS / City Weather Panel ── */}
        <div className="card" style={{ marginTop:'1rem', padding:'1.25rem' }}>
          <div style={{ fontWeight:600, fontSize:'0.9rem', color:'var(--green-900)', marginBottom:'0.75rem', display:'flex', alignItems:'center', gap:6 }}>
            <MapPin size={16} color="var(--green-700)" /> Auto-fill Weather Data (Real-time)
          </div>

          {/* GPS button */}
          <div style={{ display:'flex', gap:'0.75rem', flexWrap:'wrap', marginBottom:'0.75rem' }}>
            <button
              onClick={handleGPS}
              disabled={gpsLoading}
              style={{ display:'flex', alignItems:'center', gap:6, padding:'9px 18px', borderRadius:8, background:'var(--green-800)', color:'white', border:'none', cursor:'pointer', fontSize:'0.88rem', fontWeight:600, opacity: gpsLoading ? 0.7 : 1 }}
            >
              {gpsLoading ? <Loader size={14} className="spin" /> : <MapPin size={14} />}
              {gpsLoading ? 'Getting location…' : 'Use My GPS Location'}
            </button>

            {/* City search */}
            <div style={{ display:'flex', gap:6, flex:1, minWidth:220 }}>
              <input
                type="text" placeholder="Or type city name (e.g. Chennai)"
                value={cityInput}
                onChange={e => setCityInput(e.target.value)}
                onKeyDown={e => e.key === 'Enter' && handleCitySearch()}
                style={{ flex:1, padding:'9px 12px', borderRadius:8, border:'1.5px solid var(--gray-200)', fontSize:'0.88rem', outline:'none' }}
              />
              <button
                onClick={handleCitySearch} disabled={cityLoading || !cityInput.trim()}
                style={{ padding:'9px 16px', borderRadius:8, background:'var(--green-700)', color:'white', border:'none', cursor:'pointer', fontSize:'0.88rem', fontWeight:600, opacity: cityLoading ? 0.7 : 1 }}
              >
                {cityLoading ? '…' : 'Search'}
              </button>
            </div>
          </div>

          {gpsError && (
            <div style={{ fontSize:'0.82rem', color:'#dc2626', background:'#fee2e2', padding:'8px 12px', borderRadius:6 }}>
              {gpsError} — You can still enter values manually below.
            </div>
          )}

          {/* Weather result cards */}
          {(weatherInfo || rainfallInfo) && (
            <div style={{ display:'flex', gap:'0.75rem', flexWrap:'wrap', marginTop:'0.75rem' }}>
              {weatherInfo && (
                <div style={{ background:'var(--green-100)', borderRadius:8, padding:'10px 14px', display:'flex', gap:8, alignItems:'center', fontSize:'0.85rem' }}>
                  <Thermometer size={16} color="var(--green-700)" />
                  <div>
                    <div style={{ fontWeight:600 }}>{weatherInfo.city}, {weatherInfo.country}</div>
                    <div style={{ color:'var(--gray-600)' }}>{weatherInfo.temperature}°C · {weatherInfo.description}</div>
                    <div style={{ color:'var(--green-700)', fontSize:'0.78rem' }}>✅ Temperature auto-filled</div>
                  </div>
                </div>
              )}
              {rainfallInfo && (
                <div style={{ background:'var(--green-100)', borderRadius:8, padding:'10px 14px', display:'flex', gap:8, alignItems:'center', fontSize:'0.85rem' }}>
                  <CloudRain size={16} color="var(--green-700)" />
                  <div>
                    <div style={{ fontWeight:600 }}>Annual Rainfall</div>
                    <div style={{ color:'var(--gray-600)' }}>{rainfallInfo.annual_rainfall_mm} mm/year ({rainfallInfo.months_fetched} months)</div>
                    <div style={{ color:'var(--green-700)', fontSize:'0.78rem' }}>✅ Rainfall auto-filled from 12-month history</div>
                  </div>
                </div>
              )}
            </div>
          )}
        </div>

        {/* ── Main form ── */}
        <div className="card" style={{ marginTop:'1rem' }}>

          <div className="field">
            <label>Crop Type</label>
            <div className="select-wrap">
              <select value={form.crop} onChange={e => setForm(f => ({ ...f, crop: e.target.value }))}>
                {CROPS.map(c => <option key={c} value={c}>{c}</option>)}
              </select>
            </div>
          </div>

          <div className="field">
            <label>Season</label>
            <div className="select-wrap">
              <select value={form.season} onChange={e => setForm(f => ({ ...f, season: e.target.value }))}>
                {SEASONS.map(s => <option key={s} value={s}>{s}</option>)}
              </select>
            </div>
          </div>

          {SLIDERS.map(sl => (
            <div className="slider-wrap field" key={sl.key}>
              <div className="slider-label">
                <span style={{ display:'flex', alignItems:'center', gap:6 }}>
                  {sl.label}
                  {sl.key === 'rainfall'    && rainfallInfo && <span style={{ fontSize:'0.72rem', background:'var(--green-200)', color:'var(--green-800)', padding:'1px 6px', borderRadius:4 }}>📡 Live</span>}
                  {sl.key === 'temperature' && weatherInfo  && <span style={{ fontSize:'0.72rem', background:'var(--green-200)', color:'var(--green-800)', padding:'1px 6px', borderRadius:4 }}>📡 Live</span>}
                </span>
                <span style={{ color:'var(--green-700)', fontWeight:600 }}>{form[sl.key]}</span>
              </div>
              <input
                type="range" min={sl.min} max={sl.max} step={sl.step}
                value={form[sl.key]}
                style={{ '--val': sliderPct(form[sl.key], sl.min, sl.max) + '%' }}
                onChange={e => handleSlider(sl.key, e.target.value)}
              />
              {sl.hint && <div className="slider-hint">{sl.hint}</div>}
            </div>
          ))}

          {error && (
            <p style={{ color:'#dc2626', fontSize:'0.83rem', marginBottom:'1rem', background:'#fee2e2', padding:'10px 14px', borderRadius:8 }}>
              {error}
            </p>
          )}

          <button className="btn btn-primary btn-lg" onClick={handleSubmit} disabled={loading}>
            {loading ? 'Predicting…' : 'Predict Yield'}
          </button>
        </div>

        <p style={{ fontSize:'0.78rem', color:'var(--gray-400)', marginTop:'0.75rem', textAlign:'center' }}>
          Model trained on FAOSTAT 2015–2024 · 8,621 records · 184 countries · Prices from World Bank
        </p>
      </div>

      <style>{`.spin { animation: spin 0.8s linear infinite; } @keyframes spin { to { transform: rotate(360deg); } }`}</style>
    </div>
  );
}
